",n(t.h2,{id:"remote-state-setup",children:n(t.a,{className:"anchor",href:"#remote-state-setup",children:"Remote State Setup"})}),"
",n(t.pre,{children:n(t.code,{className:"language-hcl",metastring:'title="global/s3-remote-state/main.tf"',title:"global/s3-remote-state/main.tf",children:'# S3 bucket for Terraform state
resource "aws_s3_bucket" "terraform_state" {
  bucket = "my-org-terraform-state"

  lifecycle {
    prevent_destroy = true
  }
}

resource "aws_s3_bucket_versioning" "state" {
  bucket = aws_s3_bucket.terraform_state.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "state" {
  bucket = aws_s3_bucket.terraform_state.id
  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "aws:kms"
    }
  }
}

# DynamoDB for state locking
resource "aws_dynamodb_table" "terraform_locks" {
  name         = "terraform-state-locks"
  billing_mode = "PAY_PER_REQUEST"
  hash_key     = "LockID"

  attribute {
    name = "LockID"
    type = "S"
  }
}
'})}),"
",n(t.h2,{id:"vpc-module",children:n(t.a,{className:"anchor",href:"#vpc-module",children:"VPC Module"})}),"
",n(t.pre,{children:n(t.code,{className:"language-hcl",metastring:'title="modules/vpc/main.tf"',title:"modules/vpc/main.tf",children:'resource "aws_vpc" "main" {
  cidr_block           = var.vpc_cidr
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = merge(var.tags, {
    Name = "${var.name}-vpc"
  })
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
  tags = merge(var.tags, { Name = "${var.name}-igw" })
}

# Public subnets
resource "aws_subnet" "public" {
  count             = length(var.availability_zones)
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(var.vpc_cidr, 8, count.index)
  availability_zone = var.availability_zones[count.index]
  map_public_ip_on_launch = true

  tags = merge(var.tags, {
    Name = "${var.name}-public-${var.availability_zones[count.index]}"
    Tier = "public"
  })
}

# Private subnets
resource "aws_subnet" "private" {
  count             = length(var.availability_zones)
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(var.vpc_cidr, 8, count.index + 10)
  availability_zone = var.availability_zones[count.index]

  tags = merge(var.tags, {
    Name = "${var.name}-private-${var.availability_zones[count.index]}"
    Tier = "private"
  })
}

# NAT Gateway
resource "aws_eip" "nat" {
  count  = var.enable_nat_gateway ? 1 : 0
  domain = "vpc"
}

resource "aws_nat_gateway" "main" {
  count         = var.enable_nat_gateway ? 1 : 0
  allocation_id = aws_eip.nat[0].id
  subnet_id     = aws_subnet.public[0].id
  tags = merge(var.tags, { Name = "${var.name}-nat" })
}
'})}),"
",n(t.pre,{children:n(t.code,{className:"language-hcl",metastring:'title="modules/vpc/variables.tf"',title:"modules/vpc/variables.tf",children:'variable "name" {
  description = "Name prefix for all resources"
  type        = string
}

variable "vpc_cidr" {
  description = "CIDR block for the VPC"
  type        = string
  default     = "10.0.0.0/16"
}

variable "availability_zones" {
  description = "List of availability zones"
  type        = list(string)
}

variable "enable_nat_gateway" {
  description = "Whether to create a NAT Gateway"
  type        = bool
  default     = true
}

variable "tags" {
  description = "Tags to apply to all resources"
  type        = map(string)
  default     = {}
}
'})}),"
",n(t.h2,{id:"using-the-module",children:n(t.a,{className:"anchor",href:"#using-the-module",children:"Using the Module"})}),"
",n(t.pre,{children:n(t.code,{className:"language-hcl",metastring:'title="environments/prod/main.tf"',title:"environments/prod/main.tf",children:'terraform {
  backend "s3" {
    bucket         = "my-org-terraform-state"
    key            = "prod/terraform.tfstate"
    region         = "us-east-1"
    dynamodb_table = "terraform-state-locks"
    encrypt        = true
  }
}

provider "aws" {
  region = var.aws_region
}

module "vpc" {
  source = "../../modules/vpc"

  name               = "prod"
  vpc_cidr           = "10.0.0.0/16"
  availability_zones = ["us-east-1a", "us-east-1b", "us-east-1c"]
  enable_nat_gateway = true

  tags = {
    Environment = "production"
    Team        = "platform"
    ManagedBy   = "terraform"
  }
}
'})}),"
",n(t.h2,{id:"terraform-workflow",children:n(t.a,{className:"anchor",href:"#terraform-workflow",children:"Terraform Workflow"})}),"
",n(t.pre,{children:n(t.code,{className:"language-bash",metastring:'title="workflow.sh"',title:"workflow.sh",children:"# Initialize (download providers and modules)
terraform init

# Format code
terraform fmt -recursive

# Validate configuration
terraform validate

# Plan changes (dry run)
terraform plan -var-file=terraform.tfvars -out=tfplan

# Apply approved plan
terraform apply tfplan

# Destroy (with confirmation)
terraform destroy -var-file=terraform.tfvars
"})}),"
